CREATE TABLE IF NOT EXISTS schema_migrations (version TEXT PRIMARY KEY, applied_at TEXT NOT NULL);
CREATE TABLE providers (id TEXT PRIMARY KEY, name TEXT NOT NULL, base_url TEXT NOT NULL, terms_url TEXT, license_default TEXT, enabled INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE courses (id TEXT PRIMARY KEY, provider_id TEXT NOT NULL REFERENCES providers(id), provider_course_id TEXT NOT NULL, canonical_url TEXT NOT NULL, title TEXT NOT NULL, course_number TEXT, department TEXT, instructors_json TEXT NOT NULL DEFAULT '[]', term TEXT, level TEXT, language TEXT NOT NULL DEFAULT 'en', description TEXT, topics_json TEXT NOT NULL DEFAULT '[]', license_code TEXT, license_url TEXT, attribution_text TEXT, third_party_exceptions_possible INTEGER NOT NULL DEFAULT 1, supported_mode TEXT, teachability_score REAL, suitability_reason TEXT, catalog_state TEXT NOT NULL DEFAULT 'indexed', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(provider_id, provider_course_id));
CREATE TABLE course_suitability (id TEXT PRIMARY KEY, course_id TEXT NOT NULL REFERENCES courses(id), supported_mode TEXT NOT NULL, teachability_score REAL NOT NULL, ai_grading_reliability TEXT NOT NULL, requires_lab INTEGER NOT NULL DEFAULT 0, requires_physical_equipment INTEGER NOT NULL DEFAULT 0, requires_group_work INTEGER NOT NULL DEFAULT 0, requires_final_project INTEGER NOT NULL DEFAULT 0, requires_artifact_submission INTEGER NOT NULL DEFAULT 0, has_sufficient_transcript_or_notes INTEGER NOT NULL DEFAULT 0, has_assessments INTEGER NOT NULL DEFAULT 0, risk_flags_json TEXT NOT NULL DEFAULT '[]', evidence_json TEXT NOT NULL DEFAULT '[]', reason TEXT NOT NULL, classifier_version TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE course_assets (id TEXT PRIMARY KEY, course_id TEXT NOT NULL REFERENCES courses(id), asset_type TEXT NOT NULL, url TEXT, title TEXT, local_path TEXT, source_page_url TEXT, mime_type TEXT, size_bytes INTEGER, checksum TEXT, license_scope TEXT NOT NULL DEFAULT 'unknown', downloadable INTEGER NOT NULL DEFAULT 1, processing_state TEXT NOT NULL DEFAULT 'pending', metadata_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE content_chunks (id TEXT PRIMARY KEY, course_id TEXT NOT NULL REFERENCES courses(id), unit_id TEXT, asset_id TEXT REFERENCES course_assets(id), chunk_type TEXT NOT NULL, text TEXT NOT NULL, source_ref_json TEXT NOT NULL, token_count INTEGER, metadata_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL);
CREATE TABLE course_units (id TEXT PRIMARY KEY, course_id TEXT NOT NULL REFERENCES courses(id), parent_unit_id TEXT, unit_index INTEGER NOT NULL, title TEXT NOT NULL, description TEXT, estimated_minutes INTEGER, source_asset_ids_json TEXT NOT NULL DEFAULT '[]', concepts_json TEXT NOT NULL DEFAULT '[]', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(course_id, unit_index));
CREATE TABLE learning_goals (id TEXT PRIMARY KEY, raw_goal TEXT NOT NULL, parsed_goal_json TEXT NOT NULL, preferred_language TEXT NOT NULL DEFAULT 'zh', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE learning_paths (id TEXT PRIMARY KEY, goal_id TEXT NOT NULL REFERENCES learning_goals(id), title TEXT NOT NULL, description TEXT, depth TEXT, weekly_hours INTEGER, language TEXT NOT NULL DEFAULT 'zh', planner_version TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE learning_path_courses (id TEXT PRIMARY KEY, path_id TEXT NOT NULL REFERENCES learning_paths(id), course_id TEXT NOT NULL REFERENCES courses(id), sequence_index INTEGER NOT NULL, role TEXT NOT NULL, inclusion_reason TEXT NOT NULL, mode_override TEXT, created_at TEXT NOT NULL);
CREATE TABLE lessons (id TEXT PRIMARY KEY, unit_id TEXT NOT NULL REFERENCES course_units(id), title TEXT NOT NULL, lesson_markdown TEXT NOT NULL, audio_script TEXT, summary TEXT, source_citations_json TEXT NOT NULL, prompt_version TEXT NOT NULL, model_info_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE quiz_items (id TEXT PRIMARY KEY, lesson_id TEXT NOT NULL REFERENCES lessons(id), item_type TEXT NOT NULL, prompt TEXT NOT NULL, choices_json TEXT, correct_answer_json TEXT, rubric_json TEXT, difficulty TEXT NOT NULL DEFAULT 'medium', source_citations_json TEXT NOT NULL, origin TEXT NOT NULL DEFAULT 'generated', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE attempts (id TEXT PRIMARY KEY, quiz_item_id TEXT NOT NULL REFERENCES quiz_items(id), user_answer TEXT NOT NULL, grade_json TEXT NOT NULL, score REAL, passed INTEGER NOT NULL DEFAULT 0, confidence REAL, created_at TEXT NOT NULL);
CREATE TABLE mastery_records (id TEXT PRIMARY KEY, unit_id TEXT NOT NULL REFERENCES course_units(id), status TEXT NOT NULL, mastery_score REAL NOT NULL DEFAULT 0, weak_concepts_json TEXT NOT NULL DEFAULT '[]', last_attempt_at TEXT, next_review_at TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(unit_id));
CREATE TABLE jobs (id TEXT PRIMARY KEY, job_type TEXT NOT NULL, status TEXT NOT NULL, input_json TEXT NOT NULL, output_json TEXT, error_json TEXT, progress REAL NOT NULL DEFAULT 0, checkpoint_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, started_at TEXT, finished_at TEXT);
CREATE TABLE token_ledger (id TEXT PRIMARY KEY, provider TEXT NOT NULL, model TEXT NOT NULL, task_type TEXT NOT NULL, course_id TEXT, unit_id TEXT, input_tokens INTEGER, output_tokens INTEGER, estimated_cost_usd REAL, cache_hit INTEGER NOT NULL DEFAULT 0, prompt_version TEXT, created_at TEXT NOT NULL);
